#include <iostream>
using namespace std;

class ComplexNumber{
private:
 float real;
 float imag;

public:
 ComplexNumber(){
  real = 0;
  imag = 0;
 }

 ComplexNumber(float r,float i){
  real = r;
  imag = i;
 }

 void display(){
  cout << real << "+" << imag << "i" << endl;
 }

 ComplexNumber operator+(ComplexNumber c){
  return ComplexNumber(real + c.real, imag + c.imag);
 }

 ComplexNumber operator-(ComplexNumber c){
  return ComplexNumber(real - c.real, imag - c.imag);
 }

 bool operator==(ComplexNumber c){
  return real == c.real && imag == c.imag;
 }
};

int main(){
 ComplexNumber c1(4,5), c2(2,3);

 ComplexNumber sum = c1 + c2;
 ComplexNumber diff = c1 - c2;

 sum.display();
 diff.display();

 if(c1 == c2)
  cout << "Equal";
 else
  cout << "Not Equal";

 return 0;
}

