 while(left < right){
  if(s[left] != s[right])
   return false;

  left++;
  right--;
 }

 return true;
}

int countVowels(string s){
 int count = 0;

 for(int i=0;i<s.length();i++){
  char c = tolower(s[i]);

  if(c=='a'||c=='e'||c=='i'||c=='o'||c=='u')
   count++;
 }

 return count;
}

int countConsonants(string s){
 int count = 0;

 for(int i=0;i<s.length();i++){
  char c = tolower(s[i]);

  if(isalpha(c) && !(c=='a'||c=='e'||c=='i'||c=='o'||c=='u'))
   count++;
 }

 return count;
}

int main(){
 string s;
 getline(cin,s);

 if(isPalindrome(s))
  cout << "Palindrome" << endl;
 else
