class DataProcessor {
public:
    double computeAverage(const std::string& filename) {
        std::ifstream file(filename);
        if (!file.is_open()) {
            throw std::runtime_error("Error: Could not open file: " + filename);
        }

        int val;
        int sum = 0;
        int count = 0;

        while (file >> val) {
            sum += val;
            count++;
        }

        if (!file.eof() && file.fail()) {
            file.close();
            throw std::invalid_argument("Error: Non-integer data encountered in file.");
        }

        file.close();

        if (count == 0) {
            throw std::domain_error("Error: Cannot compute average of an empty file.");
        }

        return static_cast<double>(sum) / count;
    }
};

