            throw std::runtime_error("Error opening file");
        }
        int val;
        int sum = 0, count = 0;
        while (file >> val) {
            sum += val;
            count++;
        }
        if (file.fail()) {
            file.close();
            throw std::invalid_argument("Invalid token discovered"); 
        }
        file.close();
        if (count == 0) throw std::domain_error("Empty file");
        return static_cast<double>(sum) / count;
    }
};

